def parse_integer_answer(text: str, lo: int | None = None, hi: int | None = None) -> int | None:
    """Extract the first in-range integer from agent free text; None on failure.

    Mirrors silisocs NumericRatingProbe.parse_answer: returns the first integer
    in [lo, hi], so a preamble like "on a scale of 1 to 10 I'd say 7" parses as 7.
    """
    for m in re.finditer(r"\b(\d+)\b", str(text or "")):
        val = int(m.group(1))
        if (lo is None or val >= lo) and (hi is None or val <= hi):
            return val
    return None
